        };
        var datatable = datatableview.initialize($('.datatable'), common_options);
        // Per Column search text input initialization
        $('.datatable tfoot th').each(function(){
            var title = $('.datatable thead th').eq($(this).index()).text();
            $(this).html('<input type="text" placeholder='+title+'>');
        });
        // Per column search initialization
        var table = datatable.api();
        table.columns().every(function(){
            var column = this;
            $('input', column.footer()).on('keyup change', function(){
                if (column.search() !== this.value) {
                    column.search(this.value).draw();
                }
            });
            // Custom buttom functions for resetting column search, 
            $("#reset-columns").click( function(){
                   column.search('').draw();
                   $('input').val('');
                 });
        });
    });


  </script>`

